use std::collections::HashMap;

struct Team {
    goals_scored: u8,
    goals_conceded: u8,
}

fn build_scores_table(results: &str) -> HashMap<String, Team> {
    let mut scores = HashMap::new();

    for line in results.lines() {
        let mut split = line.split(',');
        let team_1 = split.next().unwrap().trim();
        let team_1_score: u8 = split.next().unwrap().trim().parse().unwrap();
        let team_2 = split.next().unwrap().trim();
        let team_2_score: u8 = split.next().unwrap().trim().parse().unwrap();

        let entry1 = scores.entry(team_1.to_string()).or_insert_with(|| Team { goals_scored: 0, goals_conceded: 0 });
        entry1.goals_scored += team_1_score;
        entry1.goals_conceded += team_2_score;

        let entry2 = scores.entry(team_2.to_string()).or_insert_with(|| Team { goals_scored: 0, goals_conceded: 0 });
        entry2.goals_scored += team_2_score;
        entry2.goals_conceded += team_1_score;
    }

    scores
}

fn main() {
    let results = "England,3,France,1\nFrance,2,Italy,0\nEngland,1,Italy,2";
    let scores = build_scores_table(results);
    for (team, stats) in &scores {
        println!("{}: scored={} conceded={}", team, stats.goals_scored, stats.goals_conceded);
    }
}
